// Augment next-auth types so that `session.user.id` and `session.user.role`
// are fully typed throughout the application without casting.
import 'next-auth';
import 'next-auth/jwt';

declare module 'next-auth' {
  interface Session {
    user: {
      id: string;
      name?: string | null;
      email?: string | null;
      image?: string | null;
      role: string;
    };
  }

  // Returned by the `authorize` callback and passed into the JWT callback as `user`.
  interface User {
    role: string;
  }
}

declare module 'next-auth/jwt' {
  interface JWT {
    id: string;
    role: string;
  }
}
